var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"휴우...... 치워도 치워도 끝이 없네.","JPN":"ふぅ……片付けても片付けてもキリがないなぁ。","ENG":"Whew... There's no end to the cleaning.","TWN":"呼……不論怎麼打掃都打掃不完呢。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"연락한 청소업체는 대체 언제쯤 도착하는 거람.","JPN":"連絡した清掃業者はいったいいつ頃着くんだろう。","ENG":"When is the cleaning company going to arrive?","TWN":"清潔公司也不知道什麼時候才會到。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어? 뭐죠? 청소 로봇인가요?","JPN":"あれ？　何でしょう？　お掃除ロボットでしょうか？","ENG":"Huh? What's this? Is this a cleaning robot?","TWN":"咦？ 這是什麼？ 打掃機器人嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네? 아! 죄, 죄송합니다.","JPN":"え？　あっ！　す、すみません。","ENG":"What? Oh! I-I'm sorry.","TWN":"咦？啊！對，對不起。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"이번에 새로 부임한 사장님이셨군요.","JPN":"今回新しく赴任した社長でしたか。","ENG":"You must be the new CEO.","TWN":"是新上任的老闆啊。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니 본사에 오신 것을 환영합니다.","JPN":"コフィンカンパニー本社へようこそ。","ENG":"Welcome to the Coffin Company Headquarters.","TWN":"歡迎來到科芬總公司。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"전 앞으로 사장님의 비서 역할을 맡게 된 김하나 관리부장이라고 합니다.","JPN":"私はこれから社長の秘書を務めることになりました、管理部長のナカシマ・スズカです。","ENG":"I am Manager Kim Hana. And I will be your secretary from now on.","TWN":"我是管理部長金荷娜，今後將擔任老闆的秘書。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"얼마 전까진 작전부 인력문제로 브리핑을 담당하기도 했습니다만......","JPN":"最近まで作戦部の人員不足で、ブリーフィング進行を担当していたんですけど……","ENG":"Until recently, I was in charge of mission briefings due to the Operation Department's shortage on people...","TWN":"雖然不久前，作戰部門做了一份關於人力問題的報告……"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"이번에 늘어난 예산 덕분에 숨통이 좀 트였네요.","JPN":"今回予算が増えてくれたおかげで、少し余裕ができました。","ENG":"But now we finally have some breathing room with the increased budget.","TWN":"但是這次預算增加後，總算可以鬆一口氣了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아! 아래층이요?","JPN":"あ、下の階ですか？","ENG":"Ah! Downstairs?","TWN":"啊！您說樓下嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 복합상가다 보니 좀 어수선하죠?","JPN":"やっぱり、雑居ビルだとちょっと落ち着きませんよね。","ENG":"It's a bit disordered since the building is a shopping complex.","TWN":"樓下因為是購物中心，難免會有些亂七八糟的。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그래도 임대료에 비해서 공간은 넓은 편이에요.","JPN":"それでも、この家賃にしては広い方なんですよ。","ENG":"But we have a lot of office space compared to the cost.","TWN":"但以租金來說，空間算是寬敞的了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장실도 저쪽에 마련해 놓았습니다.","JPN":"社長室は向こうに用意しておきました。","ENG":"We also prepared a room for you over there.","TWN":"我們的老闆辦公室在那邊。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"태스크포스라는 곳이 원래 현장 위주로 돌아가다 보니 주요시설들과는 좀 동떨어져 있긴 합니다만,","JPN":"タスクフォースカンパニーは元々現場メインで回っているので、他の会社とはちょっと感じが違いますけど、","ENG":"This place is a little bit away from our major facilities, since a TASKFORCE company is usually focused upon field work.","TWN":"由於特遣勢力的業務還是以現場為主，所以離主要設施比較遠，"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"회사의 주요 안건에 대한 결정은 모두 이곳 본사에서 이루어지고 있습니다.","JPN":"会社の重要案件に関する決定は、全てこの本社で行っています。","ENG":"But all major decisions regarding our company are made here at our headquarters.","TWN":"但公司的主要決策都是在總部進行。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"인재채용이나, 재무관리 등을 비롯해서......","JPN":"人材採用や財務管理はもちろん……","ENG":"You will be approving various tasks from here,","TWN":"像是招聘和財務管理……"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님께선 이곳에서 다양한 업무에 대한 결재관리를 맡게 되실 겁니다.","JPN":"社長にはここで様々な業務に関する決裁管理をしていただきます。","ENG":"including recruitment, financial management, and so on.","TWN":"老闆您會在這裡負責審批和管理各種業務。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 앞으로 잘 부탁드리겠습니다, 사장님.","JPN":"では、これからよろしくお願いいたしますね、社長。","ENG":"I look forward to working with you.","TWN":"那就請多多指教了，老闆。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};